-- Program: Plus Size HIIT
-- Category: Body-Specific -> body_specific
-- Priority: high
-- Durations: [2, 4, 8], Sessions: [3]

-- Insert branded program
INSERT INTO branded_programs (
    name, description, category, difficulty_level,
    duration_weeks, sessions_per_week, split_type,
    goals, requires_gym, is_active
) VALUES (
    'Plus Size HIIT',
    'Modified high-intensity interval training designed for plus-size individuals. All exercises are low-impact with step-based alternatives to jumping. Focus on building cardiovascular fitness, burning calories, and building confidence in a supportive progression.',
    'body_specific',
    'intermediate',
    8,
    3,
    'full_body',
    ARRAY['Maximize muscle hypertrophy', 'Time under tension', 'Maximize calorie burn', 'Preserve lean muscle', 'Build cardiovascular endurance']::text[],
    true,
    true
) ON CONFLICT (name) DO UPDATE SET
    description = EXCLUDED.description,
    category = EXCLUDED.category,
    difficulty_level = EXCLUDED.difficulty_level,
    duration_weeks = EXCLUDED.duration_weeks,
    sessions_per_week = EXCLUDED.sessions_per_week,
    split_type = EXCLUDED.split_type,
    goals = EXCLUDED.goals,
    requires_gym = EXCLUDED.requires_gym,
    updated_at = NOW();

-- Variant: Plus Size HIIT - 2w 3x/wk
INSERT INTO program_variants (
