    intensity_level,
    duration_weeks,
    variant_name,
    program_category,
    sessions_per_week,
    session_duration_minutes,
    goals,
    workouts
) SELECT
    bp.id,
    'Medium',
    2,
    'Plus Size HIIT - 2w 3x/wk',
    'body_specific',
    3,
    60,
    ARRAY['Maximize muscle hypertrophy', 'Time under tension', 'Maximize calorie burn', 'Preserve lean muscle', 'Build cardiovascular endurance']::text[],
    '[]'::jsonb
FROM branded_programs bp
WHERE bp.name = 'Plus Size HIIT'
ON CONFLICT DO NOTHING;

